def test_qexpr_sum():
    q1 = Sum(QExpr(n), (n,0,2))
    assert q1.doit() == QExpr(0) + QExpr(1) + QExpr(2)

    q2 = Sum(QExpr(n, m), (n, 0, 2), (m, 0, 2))
    assert q2.doit() == QExpr(0, 0) + QExpr(0, 1) + QExpr(0, 2) + \
        QExpr(1, 0) + QExpr(1, 1) + QExpr(1, 2) + \
        QExpr(2, 0) + QExpr(2, 1) + QExpr(2, 2)


